"use client";

import { useTransform, motion } from "framer-motion";
import { useScrollProgress } from "./ChipScroll";

const SECTIONS = [
  { progress: 0, title: "NeuralCore X1", subtitle: "The Future of AI." },
  { progress: 0.3, title: "256 Billion Parameters." },
  { progress: 0.6, title: "Built for Speed. Designed for Scale." },
  { progress: 0.9, title: "Power Your Next Breakthrough." },
] as const;

function SectionOpacity({ at, children }: { at: number; children: React.ReactNode }) {
  const { scrollYProgress } = useScrollProgress();
  const opacity = useTransform(
    scrollYProgress,
    [
      Math.max(0, at - 0.12),
      at - 0.02,
      at,
      at + 0.02,
      Math.min(1, at + 0.12),
    ],
    [0, 0.4, 1, 0.4, 0]
  );
  const y = useTransform(scrollYProgress, [at - 0.08, at, at + 0.08], [12, 0, -12]);

  return (
    <motion.div
      className="pointer-events-none absolute inset-0 flex flex-col items-center justify-center px-6 text-center"
      style={{ opacity, y }}
    >
      {children}
    </motion.div>
  );
}

export default function StoryOverlays() {
  return (
    <>
      {SECTIONS.map((section, i) => (
        <SectionOpacity key={i} at={section.progress}>
          {"subtitle" in section ? (
            <>
              <h1 className="text-4xl font-semibold tracking-tight text-white/90 min-[480px]:text-5xl md:text-6xl lg:text-7xl">
                {section.title}
              </h1>
              <p className="mt-3 text-lg tracking-tight text-white/70 min-[480px]:text-xl md:text-2xl">
                {section.subtitle}
              </p>
            </>
          ) : (
            <h2 className="text-3xl font-semibold tracking-tight text-white/90 min-[480px]:text-4xl md:text-5xl lg:text-6xl">
              {section.title}
            </h2>
          )}
        </SectionOpacity>
      ))}
    </>
  );
}
